const projects = $input.first().json.list || [];
if (projects.length === 0) throw new Error('Нет активных проектов для обновления');
return projects.map(p => ({ json: p }));

const body = $input.first().json.body || $input.first().json;
const { project_id, niche, city, domain } = body;

if (!project_id) throw new Error('project_id обязателен');
if (!niche) throw new Error('niche обязателен');

const is_cron = $execution.mode === 'trigger';
const start_time = Date.now();

return [{ json: {
  project_id,
  niche: niche || '',
  city: city || '',
  domain: domain || '',
  embed_query: `${niche || ''} ${city || ''} структура сайта SEO архитектура иерархия URL`,
  is_cron_trigger: is_cron,
  workflow_version: 'v4.0_pro',
  start_time
}}];

let ragResults = [];
try { ragResults = $('RAG Competitor Structures').first().json.result || []; } catch(e) {}

let clusterList = [];
try {
  const clusterData = $('NocoDB Get Clusters').first().json;
  clusterList = clusterData.list || (Array.isArray(clusterData) ? clusterData : []);
} catch(e) {}

let context = '';
if (ragResults.length > 0) {
  context = '=== СТРУКТУРЫ САЙТОВ ПОХОЖИХ НИШ (RAG) ===\n\n';
  ragResults.forEach((r, i) => {
    const p = r.payload || {};
    context += `Проект ${i+1} (сходство: ${Math.round(r.score*100)}%):\n`;
    context += `  Ниша: ${p.niche||''}, город: ${p.city||''}\n`;
    context += `  Страниц: ${p.pages_count||'?'}, Глубина: ${p.max_depth||'?'}\n`;
    if (p.structure_summary) {
      context += `  Структура:\n${String(p.structure_summary).substring(0, 500)}\n`;
    }
    context += '---\n';
  });
  context += '=== КОНЕЦ RAG КОНТЕКСТА ===';
}

let clusterContext = '';
if (clusterList.length > 0) {
  clusterContext = '\n\n=== КЛАСТЕРЫ СЕМАНТИЧЕСКОГО ЯДРА (из WF01) ===\n';
  clusterList.forEach(c => {
    const kws = typeof c.keywords === 'string' ? c.keywords : JSON.stringify(c.keywords || []);
    clusterContext += `\n${c.cluster_name || 'Кластер'}: ${c.main_keyword || ''}\n`;
    clusterContext += `  Тип: ${c.page_type || '?'}, Приоритет: ${c.priority || '?'}\n`;
    clusterContext += `  URL: ${c.recommended_url || '/'}\n`;
    clusterContext += `  Ключи: ${kws.substring(0, 200)}\n`;
  });
}

return [{ json: {
  rag_context: context || 'Нет данных из RAG — первый проект.',
  clusters: clusterList,
  clusters_count: clusterList.length,
  rag_sources: ragResults.length,
  rag_top_score: ragResults[0]?.score || 0,
  cluster_context: clusterContext
}}];

const inp = $('Validate Input').first().json;
const ctx = $('Format RAG + Cluster Context').first().json;
const clusters = ctx.clusters || [];

if (clusters.length === 0) {
  throw new Error('Кластеры не найдены для project_id: ' + inp.project_id + '. Сначала запустите NN_01.');
}

// Группировка кластеров по page_type для структурированного промпта
const grouped = {};
clusters.forEach(c => {
  const type = c.page_type || 'other';
  if (!grouped[type]) grouped[type] = [];
  grouped[type].push(c);
});

let clusterBlock = '';
for (const [type, items] of Object.entries(grouped)) {
  clusterBlock += `\n[${type.toUpperCase()}] (${items.length} кластеров):\n`;
  items.forEach(c => {
    clusterBlock += `  • ${c.cluster_name} | ${c.main_keyword} | приоритет: ${c.priority}`;
    if (c.recommended_url) clusterBlock += ` | url: ${c.recommended_url}`;
    if (c.search_volume) clusterBlock += ` | vol: ${c.search_volume}`;
    clusterBlock += '\n';
  });
}

const systemPrompt = `Ты Senior SEO-архитектор сайтов для российского рынка (Яндекс + Google). Год: 2026.

${ctx.rag_context}

ПРАВИЛА СТРУКТУРЫ САЙТА:
1. Максимум 3 уровня вложенности (Яндекс предпочитает плоскую структуру)
2. Главная = level 1, parent_url = null
3. Разделы каталога = level 2, parent_url = "/"
4. Подстраницы / карточки = level 3, parent_url = "/раздел/"
5. URL строго латиницей (транслитерация по ГОСТ)
6. Запрещены страницы-сироты — каждая page.parent_url ОБЯЗАНА существовать в списке pages[].url
7. Коммерческие страницы (услуги, каталог, цены) — ближе к корню (level 1-2)
8. Информационные страницы (блог, FAQ) — level 2-3
9. Обязательные страницы: /about/, /contacts/, /blog/, /otzyvy/, /faq/, /politika-konfidencialnosti/
10. Для локальных ниш добавь /rajony/ или /metro/ хаб-страницы
11. AEO/GEO: /faq/ с JSON-LD FAQPage schema (попадание в AI Overviews)
12. Каждый кластер ДОЛЖЕН быть распределён на конкретную страницу
13. Один кластер = одна страница (no keyword cannibalization)
14. Hub-and-spoke: разделы-хабы линкуют на дочерние spoke-страницы

ВАЛИДАЦИЯ:
- orphan_pages ДОЛЖЕН быть пустым массивом
- Все parent_url должны существовать в pages[].url
- Не допускай дублирование URL

ОТВЕТ: СТРОГО валидный JSON без markdown-обёрток.`;

const userPrompt = `Ниша: ${inp.niche}
Город: ${inp.city}
project_id: ${inp.project_id}
${inp.domain ? 'Домен: ' + inp.domain : ''}

КЛАСТЕРЫ (${clusters.length}):
${clusterBlock}

Сгенерируй полную SEO-оптимальную структуру сайта.

JSON формат ответа:
{
  "pages": [
    {
      "url": "/",
      "title": "Главная — [Ниша] в [Городе]",
      "h1": "[Ниша] в [Городе] — [УТП]",
      "meta_description": "..до 160 символов..",
      "parent_url": null,
      "level": 1,
      "cluster_name": "Главная",
      "page_type": "navigation",
      "priority": 1,
      "seo_role": "hub",
      "internal_links_to": ["/uslugi/", "/catalog/"],
      "schema_markup": ["Organization", "LocalBusiness"]
    }
  ],
  "total_pages": 25,
  "max_depth": 3,
  "orphan_pages": [],
  "sitemap_priority_map": {
    "/": 1.0,
    "/uslugi/": 0.9
  }
}`;

const payload = {
  model: 'llama-3.3-70b-versatile',
  max_tokens: 8192,
  temperature: 0.15,
  response_format: { type: 'json_object' },
  messages: [
    { role: 'system', content: systemPrompt },
    { role: 'user', content: userPrompt }
  ]
};

return [{ json: {
  groq_payload: payload,
  project_id: inp.project_id,
  niche: inp.niche,
  city: inp.city,
  domain: inp.domain || '',
  clusters_count: clusters.length,
  rag_sources: ctx.rag_sources,
  start_time: inp.start_time
}}];

// Guard: if LLM completely failed
const inputData = $input.first().json;
if (inputData.error || inputData.code || !inputData.choices) {
  const inp = $('Validate Input').first().json;
  return [{ json: {
    pages: [], pages_count: 0, max_depth: 0,
    project_id: inp.project_id, niche: inp.niche, city: inp.city,
    qc_score: 0, issues: ['LLM call failed completely'],
    status: 'failed', groq_tokens: 0,
    latency_ms: Date.now() - (inp.start_time || Date.now()),
    timestamp: new Date().toISOString()
  }}];
}

const groqResponse = $input.first().json;
const prev = $('Build Groq Prompt v4.0').first().json;

// ===== ROBUST JSON PARSING =====
let rawContent = groqResponse?.choices?.[0]?.message?.content || '';

// Clean BOM, markdown wrappers, trailing commas
rawContent = rawContent
  .replace(/^\uFEFF/, '')
  .replace(/```json\s*/gi, '')
  .replace(/```\s*/gi, '')
  .replace(/,\s*([}\]])/g, '$1')
  .trim();

let parsed;
try {
  parsed = JSON.parse(rawContent);
} catch(e) {
  // Try to extract JSON object
  const match = rawContent.match(/\{[\s\S]*\}/);
  if (match) {
    try {
      parsed = JSON.parse(match[0].replace(/,\s*([}\]])/g, '$1'));
    } catch(e2) {
      throw new Error('Groq вернул невалидный JSON. Первые 500 символов: ' + rawContent.slice(0, 500));
    }
  } else {
    throw new Error('JSON не найден в ответе Groq: ' + rawContent.slice(0, 300));
  }
}

// ===== VALIDATION & ENRICHMENT =====
const pages = (parsed.pages || []).map((p, idx) => {
  // Validate URL is Latin
  const url = (p.url || '/').replace(/[а-яА-ЯёЁ]/g, c => {
    const translit = {'а':'a','б':'b','в':'v','г':'g','д':'d','е':'e','ё':'yo','ж':'zh','з':'z','и':'i','й':'j','к':'k','л':'l','м':'m','н':'n','о':'o','п':'p','р':'r','с':'s','т':'t','у':'u','ф':'f','х':'kh','ц':'ts','ч':'ch','ш':'sh','щ':'shch','ъ':'','ы':'y','ь':'','э':'e','ю':'yu','я':'ya','А':'A','Б':'B','В':'V','Г':'G','Д':'D','Е':'E','Ё':'Yo','Ж':'Zh','З':'Z','И':'I','Й':'J','К':'K','Л':'L','М':'M','Н':'N','О':'O','П':'P','Р':'R','С':'S','Т':'T','У':'U','Ф':'F','Х':'Kh','Ц':'Ts','Ч':'Ch','Ш':'Sh','Щ':'Shch','Ъ':'','Ы':'Y','Ь':'','Э':'E','Ю':'Yu','Я':'Ya'};
    return translit[c] || c;
  }).toLowerCase();

  return {
    project_id: prev.project_id,
    niche: prev.niche,
    city: prev.city,
    url,
    title: p.title || 'Без названия',
    h1: p.h1 || p.title || '',
    meta_description: (p.meta_description || '').substring(0, 160),
    parent_url: p.parent_url ?? null,
    level: Math.min(p.level || 1, 3),
    cluster_name: p.cluster_name || '',
    page_type: ['commercial','informational','navigation','local','landing'].includes(p.page_type) ? p.page_type : 'navigation',
    priority: p.priority || (idx + 1),
    seo_role: p.seo_role || 'page',
    internal_links_to: p.internal_links_to || [],
    schema_markup: p.schema_markup || [],
    status: 'draft',
    version: 'v4.0',
    created: new Date().toISOString()
  };
});

// ===== STRUCTURAL VALIDATION =====
const urlSet = new Set(pages.map(p => p.url));

// Detect orphans
const orphans = pages.filter(p => p.parent_url && !urlSet.has(p.parent_url));

// Detect duplicate URLs
const urlCounts = {};
pages.forEach(p => { urlCounts[p.url] = (urlCounts[p.url] || 0) + 1; });
const duplicateUrls = Object.entries(urlCounts).filter(([_, c]) => c > 1).map(([u]) => u);

// Detect missing mandatory pages
const mandatoryPages = ['/about/', '/contacts/', '/faq/'];
const missingMandatory = mandatoryPages.filter(mp => !urlSet.has(mp));

const maxDepth = Math.max(...pages.map(p => p.level), 0);

// ===== QC SCORING =====
const issues = [];
if (pages.length === 0) issues.push('0 страниц сгенерировано');
if (pages.length < 10) issues.push(`Мало страниц: ${pages.length}`);
if (orphans.length > 0) issues.push(`${orphans.length} страниц-сирот: ${orphans.map(o=>o.url).join(', ')}`);
if (maxDepth > 3) issues.push(`Глубина ${maxDepth} > 3`);
if (duplicateUrls.length > 0) issues.push(`Дублирующиеся URL: ${duplicateUrls.join(', ')}`);
if (missingMandatory.length > 0) issues.push(`Нет обязательных: ${missingMandatory.join(', ')}`);

// Check cluster coverage
const assignedClusters = new Set(pages.map(p => p.cluster_name).filter(Boolean));
const inputClusters = $('Format RAG + Cluster Context').first().json.clusters || [];
const unmappedClusters = inputClusters.filter(c => !assignedClusters.has(c.cluster_name));
if (unmappedClusters.length > 0) issues.push(`${unmappedClusters.length} кластеров без страниц`);

let qc_score = 100;
qc_score -= orphans.length * 15;
qc_score -= duplicateUrls.length * 20;
qc_score -= missingMandatory.length * 5;
qc_score -= unmappedClusters.length * 3;
qc_score -= (maxDepth > 3 ? 15 : 0);
qc_score -= (pages.length < 10 ? 10 : 0);
qc_score = Math.max(0, Math.min(100, qc_score));

const latency_ms = Date.now() - (prev.start_time || Date.now());

return [{ json: {
  pages,
  pages_count: pages.length,
  max_depth: maxDepth,
  orphan_pages: orphans.map(o => o.url),
  duplicate_urls: duplicateUrls,
  missing_mandatory: missingMandatory,
  unmapped_clusters: unmappedClusters.map(c => c.cluster_name),
  qc_score,
  issues: issues.length > 0 ? issues : null,
  status: qc_score >= 70 ? 'ready' : (qc_score >= 40 ? 'review' : 'failed'),
  groq_tokens: groqResponse?.usage?.total_tokens || 0,
  groq_model: groqResponse?.model || 'unknown',
  project_id: prev.project_id,
  niche: prev.niche,
  city: prev.city,
  domain: prev.domain,
  clusters_count: prev.clusters_count,
  rag_sources: prev.rag_sources,
  latency_ms,
  sitemap_priority_map: parsed.sitemap_priority_map || {},
  timestamp: new Date().toISOString()
}}];

const data = $('Parse & Validate Structure').first().json;

const structSummary = data.pages
  .filter(p => p.level <= 2)
  .map(p => `${p.url} | ${p.title} | ${p.page_type} | L${p.level} | role:${p.seo_role}`)
  .join('\n');

const fullMap = data.pages
  .map(p => `L${p.level} ${p.url} → parent:${p.parent_url || 'ROOT'} | ${p.page_type} | cluster:${p.cluster_name}`)
  .join('\n');

const text = `Структура сайта v4.0\nНиша: ${data.niche}\nГород: ${data.city}\nСтраниц: ${data.pages_count}\nГлубина: ${data.max_depth}\nQC: ${data.qc_score}/100\n\nОсновная структура (L1-L2):\n${structSummary}\n\nПолная карта:\n${fullMap}`;

return [{ json: {
  project_id: data.project_id,
  niche: data.niche,
  city: data.city,
  structure_text: text,
  pages_count: data.pages_count,
  max_depth: data.max_depth,
  structure_summary: structSummary,
  qc_score: data.qc_score
}}];

const crypto = require('crypto');
const prev = $('Prepare Qdrant Embedding Text').first().json;
const vector = $input.first().json.embedding;

if (!vector || !Array.isArray(vector)) throw new Error('Invalid embedding vector');

// Deterministic ID: prevents duplicates on re-runs
const idSource = `${prev.project_id}:site_structure:${prev.niche}:${prev.city}`;
const pointId = crypto.createHash('md5').update(idSource).digest('hex').replace(/(\w{8})(\w{4})(\w{4})(\w{4})(\w{12})/, '$1-$2-$3-$4-$5');

const payload = {
  points: [{
    id: pointId,
    vector: vector,
    payload: {
      project_id: prev.project_id,
      niche: prev.niche,
      city: prev.city,
      type: 'site_structure',
      pages_count: prev.pages_count,
      max_depth: prev.max_depth,
      structure_summary: prev.structure_summary,
      qc_score: prev.qc_score,
      version: 'v4.0',
      created_at: new Date().toISOString()
    }
  }]
};

return [{ json: { qdrant_payload: payload } }];

const data = $('Parse & Validate Structure').first().json;

// Real ML features extracted from generated structure
const pages = data.pages || [];
const commercialPages = pages.filter(p => p.page_type === 'commercial').length;
const infoPages = pages.filter(p => p.page_type === 'informational').length;
const localPages = pages.filter(p => p.page_type === 'local').length;
const hubPages = pages.filter(p => p.seo_role === 'hub').length;
const spokePages = pages.filter(p => p.seo_role === 'spoke' || p.seo_role === 'page').length;
const hasSchemaMarkup = pages.some(p => (p.schema_markup || []).length > 0);
const avgLinksPerPage = pages.reduce((s, p) => s + (p.internal_links_to || []).length, 0) / Math.max(pages.length, 1);

const mlPayload = {
  total_pages: data.pages_count,
  max_depth: data.max_depth,
  commercial_pages: commercialPages,
  informational_pages: infoPages,
  local_pages: localPages,
  hub_pages: hubPages,
  spoke_pages: spokePages,
  orphan_count: data.orphan_pages.length,
  has_faq: pages.some(p => p.url.includes('/faq')),
  has_blog: pages.some(p => p.url.includes('/blog')),
  has_reviews: pages.some(p => p.url.includes('/otziv') || p.url.includes('/reviews')),
  has_schema: hasSchemaMarkup,
  avg_internal_links: Math.round(avgLinksPerPage * 100) / 100,
  commercial_ratio: Math.round((commercialPages / Math.max(data.pages_count, 1)) * 100) / 100,
  qc_score: data.qc_score
};

return [{ json: { ml_payload: mlPayload, project_id: data.project_id } }];

