const data = $('Parse & Validate Structure').first().json;

// ML result (may have failed gracefully)
let mlScore = null, mlLabel = null, mlConfidence = null;
try {
  const ml = $('ML Structure Quality').first().json;
  mlScore = ml.score ?? null;
  mlLabel = ml.label ?? null;
  mlConfidence = ml.confidence ?? null;
} catch(e) {}

// Save statuses
let nocodbOk = false, qdrantOk = false;
try { const n = $('NocoDB Bulk Save Structure').first().json; nocodbOk = Array.isArray(n) || n?.Id != null; } catch(e) {}
try { const q = $('Qdrant Upsert Structure').first().json; qdrantOk = q?.result?.status === 'acknowledged' || q?.status === 'ok'; } catch(e) {}

return [{ json: {
  status: 'success',
  project_id: data.project_id,
  niche: data.niche,
  city: data.city,
  domain: data.domain,
  pages_count: data.pages_count,
  max_depth: data.max_depth,
  orphan_pages: data.orphan_pages,
  duplicate_urls: data.duplicate_urls,
  missing_mandatory: data.missing_mandatory,
  unmapped_clusters: data.unmapped_clusters,
  qc_score: data.qc_score,
  validation_status: data.status,
  issues: data.issues,
  sitemap_priority_map: data.sitemap_priority_map,
  groq_model: data.groq_model,
  groq_tokens: data.groq_tokens,
  latency_ms: data.latency_ms,
  rag_sources: data.rag_sources,
  nocodb_saved: nocodbOk,
  qdrant_saved: qdrantOk,
  ml_structure_score: mlScore,
  ml_structure_label: mlLabel,
  ml_confidence: mlConfidence,
  version: 'v4.0_pro',
  timestamp: data.timestamp
}}];
